message GameStartUserInfo 
{
	uint32 uid = 1;
	int32 agent_id = 2;
    int64 score     = 3;//积分(deals rummy 新增)
    int32 bot_flag  = 4;//是否是机器人(deals rummy 新增)
    int32 leave_flag = 5;//是否真人已经退出此场 deals(deals rummy 新增)
    int32 game_id = 6;
    int32 level_id = 7; 
    int32 seat_id = 8;  // 座位号
    bool is_mixed = 9;  //是否混战用户
    string userInfo = 10;

    //新增:
    int32 num = 11;
    int32 kick = 12;
    int64 alloc_param = 13;   // -1 换桌  其他离开
    int64 balance = 14; //钱
    bool bLeave = 15;   //离开标志
    int64 nBetOrderId = 16;	// 下注预扣订单交易序号	
    string user_conf = 17; //用户个人配置 数值相关 json格式
    bool is_last_rebuy = 18; //是否是最后阶段rebuy机会
}

// 比赛游戏开始
message GameStartReq
{
    int32 table_id = 1;   //桌子id
    string match_data = 2;  // 赛事数据 json格式
    string table_conf = 3; // 桌子配置 json格式
    repeated GameStartUserInfo user_list = 4; // 玩家数据（包含数值发牌）
}

// 游戏服结算上报
message GameResultReportReq
{
    message User 
    {
		uint32 uid = 1;
        int64 score = 2;
        int32 seatid = 3;
        int32 operation_time = 4;   // 该局玩家操作花费时间
        int32 wrong_card_num = 5; // 异常行为-错牌次数
    }
    string match_instance_id = 1;//赛事实例id
    int32 table_id = 2;
    repeated User user_list = 3;
    int32 round_time = 4;     // 该局花费秒数
}

// 强制结束当前桌子游戏
message GameForcedEndReq
{
    string match_instance_id = 1;
    repeated int32 table_id = 2; 
}

// 用户离开
message GameUserLeaveReq
{
    uint32 uid          = 1;
    int32 agent_id      = 2;
}

message GameUserGetTableInfoReq
{
    uint32 uid = 1;
    string match_instance_id = 2;
    int32 table_id = 3;
}

// 游戏服上报退休
message ReportRoomRetire
{
    int32 svid          = 1;
    int32 status        = 2;
}

// 游戏服启动进程上报游戏服信息
message ReportRoomData
{
    int32 svid          = 1;
    int32 game_id       = 2;
