message GameWaitPush
{
    int32 game_id = 1;//游戏id 
    int64 match_id = 2;//赛事id
    string match_instance_id = 3;//赛事实例id
    int32 status = 4; // 比赛状态   
    int32 total_lv_num = 5;//总阶段数
    int32 cur_lv = 6;//当前阶段
    int32 cur_rank = 7;//当前排名
    int32 next_lv_num = 8;//晋级人数
    int32 not_finish_num = 9;//未完成桌数
