message Poster
{
    int32 id = 1;
    string url = 2;
}

message SharePoster
{
    string title = 1;
    string share_url = 2;
    string telegram = 3;
    string whatsapp = 4;
    repeated Poster poster = 5;
}

//在SharePosterResp的基础上,合入了对应分享配置的内容
message SharePosterMixed
{
    uint32 game = 1;
    uint32 share_type = 2;
    string invite_code = 3;
    SharePoster data = 4;
    int32 reward_cond = 5;  //派奖条件: 1 分享即派奖 2 注册即派奖  3 有效裂变派奖
    int32 show_flags = 6;	//第0bit位表示是否显示下载图片, 
                            //第1bit位表示是否显示复制链接, 
                            //第2bit位表示是否显示二维码
    repeated string download_pics = 7;   //分享的背景图  第一张是竖版  第二张是横板
    uint32 sub_type = 8; //子類型  
}

message Reward
{
    int64 id = 1;   //奖励ID
    int32 type = 2; // 奖励类型  1 2 
    int64 num = 3; //奖励数量
}

// 比赛结束/淘汰
message GameResultPush
{
    int64 rank = 1; //名次
    repeated Reward reward_list = 2; //奖励列表
    SharePoster data = 3; // 分享海报
    int32 task_id = 4; //任务配置id
    bool is_new_player = 5; // 是否爽局
    int32 match_type = 6; // 赛事类型
    string match_name = 7; //赛事名称

	bool is_open = 8;			//总开关
	bool begin_time_switch = 9;	//开赛时间开关
	bool winning_switch = 10;			//奖金开关
	bool regist_switch = 11;			//报名费开关
    bool share_auto_screenshot = 12;    //分享自动截图开关 爽局用的
    SharePosterMixed mix_data = 13;    //分享海报新 
    string match_instance_id = 14;//赛事实例id
    uint32 share_num = 15;          //联赛分享次数
}

